// Return sanitized env var status from the n8n container
const KEYS = [
  // Telegram
  { key: 'TELEGRAM_BOT_TOKEN', category: 'telegram', label: 'Bot Token' },
  { key: 'TELEGRAM_OWNER_CHAT_ID', category: 'telegram', label: 'Owner Chat ID' },
  // WhatsApp
  { key: 'WHATSAPP_TOKEN', category: 'whatsapp', label: 'Access Token' },
  { key: 'WHATSAPP_PHONE_NUMBER_ID', category: 'whatsapp', label: 'Phone Number ID' },
  // Twilio
  { key: 'TWILIO_ACCOUNT_SID', category: 'twilio', label: 'Account SID' },
  { key: 'TWILIO_AUTH_TOKEN', category: 'twilio', label: 'Auth Token' },
  { key: 'TWILIO_FROM_NUMBER', category: 'twilio', label: 'From Number' },
  // Anthropic
  { key: 'ANTHROPIC_API_KEY', category: 'anthropic', label: 'API Key' },
  // n8n
  { key: 'N8N_API_KEY', category: 'n8n', label: 'API Key' },
  { key: 'N8N_HOST', category: 'n8n', label: 'Host' },
  { key: 'WEBHOOK_URL', category: 'n8n', label: 'Webhook Base URL' },
  { key: 'GENERIC_TIMEZONE', category: 'n8n', label: 'Timezone' },
  // Google
  { key: 'GOOGLE_DRIVE_ROOT_FOLDER', category: 'google', label: 'Drive Root Folder' },
  { key: 'GOOGLE_DRIVE_UNSORTED_FOLDER', category: 'google', label: 'Drive Unsorted Folder' },
  { key: 'GOOGLE_SHEET_REGISTRY_ID', category: 'google', label: 'Sheet Registry ID' },
  // n8n DB
  { key: 'DB_TYPE', category: 'database', label: 'DB Type' },
  { key: 'DB_POSTGRESDB_HOST', category: 'database', label: 'DB Host' },
  { key: 'DB_POSTGRESDB_PORT', category: 'database', label: 'DB Port' },
  { key: 'DB_POSTGRESDB_DATABASE', category: 'database', label: 'DB Name' },
  { key: 'DB_POSTGRESDB_USER', category: 'database', label: 'DB User' },
  { key: 'DB_POSTGRESDB_PASSWORD', category: 'database', label: 'DB Password' }
];

function maskValue(value) {
  if (!value) return '';
  if (value.length <= 8) return '****';
  return value.slice(0, 6) + '...' + value.slice(-4);
}

const vars = KEYS.map(v => {
  const value = $env[v.key] || '';
  return {
    key: v.key,
    category: v.category,
    label: v.label,
    container: 'n8n',
    configured: value.length > 0,
    masked: maskValue(value),
    length: value.length
  };
});

return [{ json: { vars, server: 'n8n', timestamp: new Date().toISOString() } }];
